const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { DynamoDBClient } = require('@aws-sdk/client-dynamodb');
const { DynamoDBDocumentClient, UpdateCommand, GetCommand } = require('@aws-sdk/lib-dynamodb');
const crypto = require('crypto');

const sqsClient = new SQSClient({ region: process.env.AWS_REGION || 'us-east-1' });
const dynamoClient = new DynamoDBClient({ region: process.env.AWS_REGION || 'us-east-1' });
const docClient = DynamoDBDocumentClient.from(dynamoClient);

const QUEUE_URL = process.env.SQS_QUEUE_URL;
const TRANSACTIONS_TABLE = process.env.TRANSACTIONS_TABLE;
const ACCOUNTS_TABLE = process.env.ACCOUNTS_TABLE;
const MAX_TRANSACTION_AMOUNT = 1000000;
const ALLOWED_CURRENCIES = ['USD', 'EUR', 'GBP'];
const ALLOWED_TRANSACTION_TYPES = ['DEBIT', 'CREDIT', 'TRANSFER'];

class ValidationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ValidationError';
  }
}

function validateTransactionMessage(message) {
  if (!message || typeof message !== 'object') {
    throw new ValidationError('Invalid message format');
  }

  const { transactionId, accountId, amount, currency, type, timestamp } = message;

  if (!transactionId || typeof transactionId !== 'string' || !/^[a-zA-Z0-9-]{1,100}$/.test(transactionId)) {
    throw new ValidationError('Invalid transactionId');
  }

  if (!accountId || typeof accountId !== 'string' || !/^[a-zA-Z0-9-]{1,100}$/.test(accountId)) {
    throw new ValidationError('Invalid accountId');
  }

  if (typeof amount !== 'number' || isNaN(amount) || amount <= 0 || amount > MAX_TRANSACTION_AMOUNT) {
    throw new ValidationError('Invalid amount');
  }

  if (!ALLOWED_CURRENCIES.includes(currency)) {
    throw new ValidationError('Invalid currency');
  }

  if (!ALLOWED_TRANSACTION_TYPES.includes(type)) {
    throw new ValidationError('Invalid transaction type');
  }

  if (!timestamp || typeof timestamp !== 'number' || timestamp > Date.now() + 60000) {
    throw new ValidationError('Invalid timestamp');
  }

  if (message.toAccountId && !/^[a-zA-Z0-9-]{1,100}$/.test(message.toAccountId)) {
    throw new ValidationError('Invalid toAccountId');
  }

  return true;
}

async function checkIdempotency(transactionId) {
  try {
    const result = await docClient.send(new GetCommand({
      TableName: TRANSACTIONS_TABLE,
      Key: { transactionId },
      ProjectionExpression: 'transactionId'
    }));

    if (result.Item) {
      console.warn(`Duplicate transaction detected: ${transactionId}`);
      return false;
    }
    return true;
  } catch (error) {
    console.error('Idempotency check failed:', error.message);
    throw error;
  }
}

async function processTransaction(message) {
  validateTransactionMessage(message);

  const isUnique = await checkIdempotency(message.transactionId);
  if (!isUnique) {
    return { status: 'duplicate', transactionId: message.transactionId };
  }

  const sanitizedMessage = {
    transactionId: message.transactionId,
    accountId: message.accountId,
    amount: Math.round(message.amount * 100) / 100,
    currency: message.currency,
    type: message.type,
    timestamp: message.timestamp,
    processedAt: Date.now()
  };

  if (message.toAccountId) {
    sanitizedMessage.toAccountId = message.toAccountId;
  }

  try {
    await docClient.send(new UpdateCommand({
      TableName: TRANSACTIONS_TABLE,
      Key: { transactionId: sanitizedMessage.transactionId },
      UpdateExpression: 'SET accountId = :accountId, amount = :amount, currency = :currency, #type = :type, #timestamp = :timestamp, processedAt = :processedAt, #status = :status',
      ExpressionAttributeNames: {
        '#type': 'type',
        '#timestamp': 'timestamp',
        '#status': 'status'
      },
      ExpressionAttributeValues: {
        ':accountId': sanitizedMessage.accountId,
        ':amount': sanitizedMessage.amount,
        ':currency': sanitizedMessage.currency,
        ':type': sanitizedMessage.type,
        ':timestamp': sanitizedMessage.timestamp,
        ':processedAt': sanitizedMessage.processedAt,
        ':status': 'PROCESSED'
      },
      ConditionExpression: 'attribute_not_exists(transactionId)'
    }));

    const balanceChange = sanitizedMessage.type === 'DEBIT' ? -sanitizedMessage.amount : sanitizedMessage.amount;

    await docClient.send(new UpdateCommand({
      TableName: ACCOUNTS_TABLE,
      Key: { accountId: sanitizedMessage.accountId },
      UpdateExpression: 'SET balance = balance + :change, lastUpdated = :now',
      ConditionExpression: 'attribute_exists(accountId) AND balance + :change >= :minBalance',
      ExpressionAttributeValues: {
        ':change': balanceChange,
        ':now': Date.now(),
        ':minBalance': 0
      }
    }));

    console.log(`Transaction processed successfully: ${sanitizedMessage.transactionId}`);
    return { status: 'success', transactionId: sanitizedMessage.transactionId };

  } catch (error) {
    if (error.name === 'ConditionalCheckFailedException') {
      console.error(`Transaction failed - condition not met: ${sanitizedMessage.transactionId}`);
      throw new Error('Transaction condition failed');
    }
    throw error;
  }
}

async function pollMessages() {
  try {
    const command = new ReceiveMessageCommand({
      QueueUrl: QUEUE_URL,
      MaxNumberOfMessages: 10,
      WaitTimeSeconds: 20,
      VisibilityTimeout: 30,
      MessageAttributeNames: ['All']
    });

    const response = await sqsClient.send(command);

    if (response.Messages && response.Messages.length > 0) {
      for (const sqsMessage of response.Messages) {
        try {
          const messageBody = JSON.parse(sqsMessage.Body);
          
          await processTransaction(messageBody);

          await sqsClient.send(new DeleteMessageCommand({
            QueueUrl: QUEUE_URL,
            ReceiptHandle: sqsMessage.ReceiptHandle
          }));

        } catch (error) {
          if (error instanceof ValidationError) {
            console.error(`Validation error: ${error.message}`);
            await sqsClient.send(new DeleteMessageCommand({
              QueueUrl: QUEUE_URL,
              ReceiptHandle: sqsMessage.ReceiptHandle
            }));
          } else {
            console.error(`Processing error: ${error.message}`);
          }
        }
      }
    }
  } catch (error) {
    console.error('Error polling messages:', error.message);
  }
}

async function startConsumer() {
  console.log('Starting SQS consumer for financial transactions...');
  
  if (!QUEUE_URL || !TRANSACTIONS_TABLE || !ACCOUNTS_TABLE) {
    throw new Error('Missing required environment variables');
  }

  while (true) {
    await pollMessages();
  }
}

startConsumer().catch(error => {
  console.error('Fatal error:', error.message);
  process.exit(1);
});